('gyro_trinidad_style_trinidadian', 'Gyro (Trinidad Style)', 380, 22, 38, 15, 2, 4, 250, 250, 'research', ARRAY['gyro (trinidad style)', 'gyro trinidad', 'street gyro'], 'street_food', NULL, 1, 'TT', 'A Trinidadian adaptation of the gyro featuring seasoned meat (chicken or lamb) in pita-style bread with local condiments including chadon beni sauce and pepper sauce. Common at street food festivals.', TRUE),
('channa_aloo_street_style_trinidadian', 'Channa Aloo (Street Style)', 175, 7, 30, 4, 5, 2, 200, NULL, 'research', ARRAY['channa aloo (street style)', 'curried channa and aloo', 'chickpea potato curry'], 'street_food', NULL, 1, 'TT', 'Curried chickpeas and potato in a light sauce, sold in cups by street vendors. A vegetarian street staple often eaten on its own or as a side with roti.', TRUE),
('curry_mango_trinidadian', 'Curry Mango', 90, 1, 20, 1, 2, 14, 150, NULL, 'research', ARRAY['curry mango', 'curried green mango', 'mango curry tt'], 'street_food', NULL, 1, 'TT', 'Green mango cooked in curry spices until tender — a beloved Trinidadian side dish and street snack. Eaten with roti or plain rice, it captures the island''s love of combining sour and spicy flavours.', TRUE),
('tamarind_balls_trinidadian', 'Tamarind Balls', 280, 2, 68, 1, 3, 55, 50, 15, 'research', ARRAY['tamarind balls', 'tamarind candy', 'tambran ball'], 'traditional_sweets', NULL, 1, 'TT', 'Tamarind pulp rolled with sugar and pepper into small balls — one of Trinidad''s most iconic traditional sweets. Sold in school tuck shops, at markets and by street vendors. A nostalgic childhood favourite.', TRUE),
('mithai_trinidadian', 'Mithai', 430, 6, 58, 20, 1, 38, 50, 15, 'research', ARRAY['mithai', 'indian sweet tt', 'divali mithai'], 'traditional_sweets', NULL, 1, 'TT', 'Traditional Indian-Trinidadian sweet made from flour, ghee and sugar, fried and coated with sugar syrup. Distributed during Hindu festivals like Divali and Phagwa as a sacred offering.', TRUE),
('barfi_trinidadian', 'Barfi', 410, 8, 55, 18, 1, 48, 50, 25, 'research', ARRAY['barfi', 'burfi', 'milk fudge sweet tt'], 'traditional_sweets', NULL, 1, 'TT', 'Milk-based Indian sweet made with condensed milk and flavoured with cardamom, rosewater or coconut. A staple at Trinidadian Hindu festivals and weddings, part of the island''s rich Indo-Caribbean culinary heritage.', TRUE),
('parsad_trinidadian', 'Parsad', 340, 5, 50, 14, 1, 28, 50, NULL, 'research', ARRAY['parsad', 'wheat parsad', 'puja sweet tt'], 'traditional_sweets', NULL, 1, 'TT', 'Similar to prasad, this wheat flour-based sweet is made with ghee and sugar for Hindu religious ceremonies. The name reflects the local Trinidadian pronunciation and slight variation in recipe.', TRUE),
('ladoo_trinidadian', 'Ladoo', 420, 7, 58, 18, 2, 35, 50, 30, 'research', ARRAY['ladoo', 'besan ladoo', 'laddu tt', 'round sweet ball'], 'traditional_sweets', NULL, 1, 'TT', 'Round sweet balls made from gram flour, ghee, sugar and cardamom — a Hindu festival sweet distributed at Divali, weddings and pujas. Part of Trinidad''s vibrant Hindu cultural celebrations.', TRUE),
('rasgulla_trinidadian', 'Rasgulla', 180, 5, 34, 4, 0, 28, 100, 35, 'research', ARRAY['rasgulla', 'rasgola tt', 'cheese ball sweet'], 'traditional_sweets', NULL, 1, 'TT', 'Spongy white cheese balls (chenna) cooked in light sugar syrup — a Bengali-origin Indian sweet brought to Trinidad by indentured labourers. Served chilled at Hindu festivals.', TRUE),
('kheer_rice_pudding_trinidadian', 'Kheer (Rice Pudding)', 150, 5, 24, 4, 0, 16, 200, NULL, 'research', ARRAY['kheer (rice pudding)', 'rice kheer', 'sweet rice pudding tt'], 'traditional_sweets', NULL, 1, 'TT', 'Creamy rice pudding made with whole milk, rice, sugar, cardamom and raisins — a traditional Indian-Trinidadian dessert served at pujas and religious celebrations.', TRUE),
('sawine_trinidadian', 'Sawine', 200, 5, 30, 7, 1, 18, 200, NULL, 'research', ARRAY['sawine', 'seviyan', 'vermicelli sweet milk', 'eid sawine'], 'traditional_sweets', NULL, 1, 'TT', 'Vermicelli noodles cooked in sweet milk with cinnamon, raisins and spices — a traditional Muslim-Trinidadian dessert made for Eid celebrations. A beloved sweet in Trinidad''s Muslim community.', TRUE),
('bora_yardlong_bean_curry_trinidadian', 'Bora (Yardlong Bean Curry)', 110, 5, 16, 3, 4, 3, 150, NULL, 'research', ARRAY['bora (yardlong bean curry)', 'bodi curry', 'curried long beans', 'yardlong bean curry'], 'street_food', NULL, 1, 'TT', 'Curried yardlong beans (bora/bodi) cooked with garlic, cumin, pepper and turmeric. A staple vegetable side dish in both Indian and Creole Trinidadian cooking, often served with roti.', TRUE),
('jelly_coconut_trinidadian', 'Jelly Coconut', 35, 1, 5, 1, 1, 4, 150, NULL, 'research', ARRAY['jelly coconut', 'jelly nut', 'soft coconut jelly', 'coconut jelly tt'], 'street_food', NULL, 1, 'TT', 'Young coconut with soft jelly flesh scooped out after drinking the water. The vendor splits the nut and fashions a spoon from the shell. A refreshing and iconic roadside experience in Trinidad.', TRUE),
('sugarcane_juice_trinidadian', 'Sugarcane Juice', 70, 0, 17, 0, 0, 17, 250, NULL, 'research', ARRAY['sugarcane juice', 'cane juice', 'fresh sugarcane juice'], 'street_food', NULL, 1, 'TT', 'Fresh juice pressed from raw sugarcane stalks, sold cold by vendors. A refreshing street drink that reflects Trinidad''s history as a major sugarcane producer in the colonial era.', TRUE),
('plum_pommecythere_trinidadian', 'Plum (Pommecythere)', 55, 1, 13, 0, 2, 10, 100, 60, 'research', ARRAY['plum (pommecythere)', 'golden apple', 'june plum', 'pommecythere tt', 'cythere'], 'street_food', NULL, 1, 'TT', 'Also called golden apple (June plum), eaten green with salt and pepper or ripe. Street vendors sell pommecythere curried, pickled or fresh. A quintessential Trinidadian school gate snack.', TRUE),
('curried_pommecythere_trinidadian', 'Curried Pommecythere', 80, 1, 18, 1, 2, 12, 150, NULL, 'research', ARRAY['curried pommecythere', 'curried golden apple', 'curried cythere'], 'street_food', NULL, 1, 'TT', 'Green pommecythere (golden apple) cooked in a light curry sauce with shadow beni and pepper. Sold by street vendors and eaten as a snack or side dish throughout Trinidad.', TRUE),
('pommecythere_chutney_trinidadian', 'Pommecythere Chutney', 65, 0, 16, 0, 2, 12, 80, NULL, 'research', ARRAY['pommecythere chutney', 'golden apple chutney', 'cythere chutney'], 'condiment', NULL, 1, 'TT', 'Tangy chutney made from green pommecythere blended with garlic, shadow beni, hot pepper and sometimes mango. Used as a condiment with doubles, roti and fried foods.', TRUE),
('shadow_beni_sauce_chadon_beni_trinidadian', 'Shadow Beni Sauce (Chadon Beni)', 35, 1, 5, 1, 1, 1, 30, NULL, 'research', ARRAY['shadow beni sauce (chadon beni)', 'chadon beni sauce', 'shadow benny sauce', 'green seasoning tt'], 'condiment', NULL, 1, 'TT', 'Blended sauce made from shadow beni (culantro/chadon beni), garlic, lime and hot pepper. A uniquely Trinidadian green condiment used on virtually every street food and home-cooked meal.', TRUE),
('roast_corn_street_trinidadian', 'Roast Corn (Street)', 120, 4, 24, 2, 3, 5, 150, 150, 'research', ARRAY['roast corn (street)', 'roasted corn tt', 'coal-roasted corn', 'corn on the cob street'], 'street_food', NULL, 1, 'TT', 'Corn on the cob roasted over open coals by street vendors, brushed with butter and pepper sauce. A beloved Trinidadian evening snack, especially popular along the Savannah and at cricket matches.', TRUE),
('boiled_corn_street_trinidadian', 'Boiled Corn (Street)', 100, 3, 21, 1, 2, 4, 150, 150, 'research', ARRAY['boiled corn (street)', 'boiled cob', 'coconut corn tt'], 'street_food', NULL, 1, 'TT', 'Whole ears of corn boiled in salted water with coconut milk, sold by street vendors. Served with butter and salt, it is a simple, affordable snack available islandwide.', TRUE),
('corn_pudding_trinidadian', 'Corn Pudding', 190, 4, 32, 6, 2, 14, 150, NULL, 'research', ARRAY['corn pudding', 'corn and coconut pudding', 'baked corn pudding'], 'traditional_sweets', NULL, 1, 'TT', 'A baked pudding made from grated coconut, cornmeal, sugar, and spices like nutmeg and cinnamon. A traditional Afro-Trinidadian dessert associated with village celebrations and Sunday cooking.', TRUE),
('fudge_coconut_fudge_trinidadian', 'Fudge (Coconut Fudge)', 420, 3, 65, 17, 2, 56, 40, 20, 'research', ARRAY['fudge (coconut fudge)', 'trinidad coconut fudge', 'milk fudge tt'], 'traditional_sweets', NULL, 1, 'TT', 'Soft coconut fudge made with condensed milk, coconut, butter and vanilla. Formed into squares and wrapped in wax paper, it is a classic Trinidadian sweet sold at fairs, markets and school fundraisers.', TRUE),
('nut_cake_peanut_cake_trinidadian', 'Nut Cake (Peanut Cake)', 440, 12, 50, 23, 3, 38, 50, 30, 'research', ARRAY['nut cake (peanut cake)', 'peanut brittle tt', 'groundnut cake', 'nut sweet'], 'traditional_sweets', NULL, 1, 'TT', 'A caramelised peanut brittle-style sweet made by cooking peanuts in sugar syrup until crystallised into blocks. A traditional Trinidadian market sweet, part of the island''s African and Indian candy-making heritage.', TRUE),
('chip_chip_street_snack_trinidadian', 'Chip Chip (Street Snack)', 150, 10, 12, 5, 0, 1, 100, NULL, 'research', ARRAY['chip chip (street snack)', 'chip chip and lime', 'beach chip chip', 'tiny clam tt'], 'street_food', NULL, 1, 'TT', 'Tiny shellfish (chip chip) boiled and tossed with lime, pepper and chadon beni. Harvested from the beaches of Tobago and South Trinidad, these bivalves are a local delicacy sold by seaside vendors.', TRUE),
('oyster_cocktail_trinidad_trinidadian', 'Oyster Cocktail (Trinidad)', 95, 10, 8, 2, 0, 3, 150, NULL, 'research', ARRAY['oyster cocktail (trinidad)', 'oyster cocktail tt', 'raw oysters street'], 'street_food', NULL, 1, 'TT', 'Raw or lightly pickled oysters served in a cup with tomato-based cocktail sauce, hot pepper and lime. Sold by vendors at the Queen''s Park Savannah and beach areas — a bold street food experience.', TRUE),
('wingstop_style_chicken_tt_street_trinidadian', 'Wingstop Style Chicken (TT Street)', 310, 26, 14, 17, 1, 2, 150, NULL, 'research', ARRAY['wingstop style chicken (tt street)', 'fried chicken wings tt', 'seasoned wings street'], 'street_food', NULL, 1, 'TT', 'Seasoned chicken wings deep-fried and tossed in various sauces — a popular modern street food style in Trinidad that blends American fast food influence with local seasonings like green seasoning and hot pepper.', TRUE),
('fried_chicken_street_stall_trinidadian', 'Fried Chicken (Street Stall)', 295, 25, 12, 17, 1, 1, 150, NULL, 'research', ARRAY['fried chicken (street stall)', 'roadside fried chicken', 'trini fried chicken', 'stall chicken'], 'street_food', NULL, 1, 'TT', 'Chicken pieces marinated in green seasoning, garlic and scotch bonnet, then deep-fried until golden. A staple at Trinidadian street food stalls, roadside vendors and school canteens.', TRUE),
('bbq_chicken_savannah_trinidadian', 'BBQ Chicken (Savannah)', 240, 28, 8, 10, 0, 6, 150, NULL, 'research', ARRAY['bbq chicken (savannah)', 'savannah bbq', 'charcoal grilled chicken tt', 'bbq half chicken'], 'street_food', NULL, 1, 'TT', 'Barbecued chicken halves or pieces cooked on charcoal grills at the Queen''s Park Savannah in Port of Spain — a tradition particularly strong on weekends. Basted with BBQ sauce and served with bread.', TRUE),
('corn_dumplings_trinidadian', 'Corn Dumplings', 185, 4, 36, 3, 3, 2, 100, 40, 'research', ARRAY['corn dumplings', 'cornmeal dumplings', 'corn soup dumplings'], 'traditional', NULL, 1, 'TT', 'Dumplings made from cornmeal and flour, boiled in soups and stews. A staple ingredient in corn soup and other traditional Trinidadian soups, providing substance to the dish.', TRUE),
('flour_dumplings_trinidadian', 'Flour Dumplings', 220, 6, 44, 3, 2, 1, 100, 40, 'research', ARRAY['flour dumplings', 'boiled dumplings tt', 'soup dumplings', 'spinners tt'], 'traditional', NULL, 1, 'TT', 'Plain boiled or fried flour dumplings added to soups, stews and provisions meals. A staple of Afro-Trinidadian cooking, these simple dumplings are found in Sunday soups and oil downs.', TRUE),
('hallaca_trinidadian', 'Hallaca', 265, 10, 35, 10, 3, 3, 180, 180, 'research', ARRAY['hallaca', 'trinidad hallaca', 'venezuelan-style pastelle'], 'carnival_foods', NULL, 1, 'TT', 'Similar to pastelle but influenced by the Venezuelan hallaca — a corn dough parcel filled with stewed meat, wrapped in plantain leaves and boiled. A festive food eaten during Christmas season in Trinidad.', TRUE),
('cucumber_chow_trinidadian', 'Cucumber Chow', 30, 1, 6, 0, 1, 3, 150, NULL, 'research', ARRAY['cucumber chow', 'cucumber doubles topping', 'chow cucumber'], 'street_food', NULL, 1, 'TT', 'Sliced cucumber seasoned with shadow beni, garlic, pepper and lime. Served as a topping on doubles and as a standalone street snack, especially refreshing in Trinidad''s tropical heat.', TRUE),
('fried_plantain_trinidadian', 'Fried Plantain', 220, 2, 44, 5, 3, 18, 100, NULL, 'research', ARRAY['fried plantain', 'sweet fried plantain', 'ripe plantain fried', 'maduros tt'], 'street_food', NULL, 1, 'TT', 'Ripe plantain sliced and pan-fried in oil until caramelised and golden. A popular side dish in Trinidadian Creole cooking served alongside rice, stewed meat and peas.', TRUE),
('accra_salt_cod_fritters_trinidadian', 'Accra (Salt Cod Fritters)', 265, 14, 24, 12, 1, 1, 100, 30, 'research', ARRAY['accra (salt cod fritters)', 'saltfish accra', 'salt cod fritters tt', 'stamp and go tt'], 'street_food', NULL, 1, 'TT', 'Deep-fried fritters made from saltfish (salt cod) mixed into a seasoned flour batter with shadow beni, pepper and onion. An Afro-Caribbean street food with roots in West Africa, popular at fetes and fairs.', TRUE),
('corn_fritters_trinidadian', 'Corn Fritters', 240, 5, 32, 11, 2, 4, 100, 30, 'research', ARRAY['corn fritters', 'fried corn fritters', 'corn cakes tt'], 'street_food', NULL, 1, 'TT', 'Fritters made with corn kernels mixed into a seasoned batter and deep-fried. A popular street food snack enjoyed at markets and fairs across Trinidad.', TRUE),
('aloo_roti_trinidadian', 'Aloo Roti', 290, 7, 46, 9, 3, 2, 150, 150, 'research', ARRAY['aloo roti', 'aloo puri', 'potato roti', 'stuffed aloo roti'], 'street_food', NULL, 1, 'TT', 'Roti flatbread stuffed with spiced mashed potato (aloo) filling and roasted on a tawa. A lighter alternative to dhalpuri that is a popular lunch and breakfast item at roti shops.', TRUE),
('curry_chicken_roti_shop_trinidadian', 'Curry Chicken (Roti Shop)', 210, 22, 8, 10, 2, 2, 200, NULL, 'research', ARRAY['curry chicken (roti shop)', 'curry chicken tt', 'roti shop curry chicken'], 'street_food', NULL, 1, 'TT', 'Bone-in chicken pieces cooked in Trinidad-style curry with shadow beni, garlic, cumin and scotch bonnet. The most popular roti shop filling across Trinidad — sold wrapped in roti or over rice.', TRUE),
('curry_lamb_trinidadian', 'Curry Lamb', 250, 22, 4, 16, 1, 1, 200, NULL, 'research', ARRAY['curry lamb', 'curried lamb tt', 'curry goat tt', 'mutton curry'], 'street_food', NULL, 1, 'TT', 'Lamb or goat slow-cooked in Trinidad-style curry powder with garlic, shadow beni and scotch bonnet. A popular roti filling, especially in the Muslim-Trinidadian and Indo-Trinidadian communities.', TRUE),
('baigan_choka_trinidadian', 'Baigan Choka', 75, 2, 8, 4, 3, 4, 150, NULL, 'research', ARRAY['baigan choka', 'eggplant choka', 'bigan choka', 'roasted eggplant tt'], 'traditional', NULL, 1, 'TT', 'Fire-roasted eggplant (baigan) mashed with garlic, oil, shadow beni and pepper. Eaten with sada roti for breakfast — a traditional Trinidadian morning meal with Indian roots adapted to Caribbean ingredients.', TRUE),
('potato_choka_trinidadian', 'Potato Choka', 110, 2, 22, 3, 2, 2, 150, NULL, 'research', ARRAY['potato choka', 'aloo choka', 'potato and roti', 'fried aloo choka'], 'traditional', NULL, 1, 'TT', 'Boiled and mashed potato seasoned with sautéed garlic and oil, shadow beni and pepper. A simple vegetarian side served with sada roti for breakfast in Trinidad.', TRUE),
('pumpkin_talkari_trinidadian', 'Pumpkin Talkari', 80, 2, 14, 2, 2, 5, 150, NULL, 'research', ARRAY['pumpkin talkari', 'pumpkin curry tt', 'stewed pumpkin tt'], 'traditional', NULL, 1, 'TT', 'Spiced pumpkin sautéed with garlic, cumin, shadow beni and pepper. A traditional Trinidadian vegetable side dish eaten with roti or rice — a staple of both Indo-Trinidadian and Afro-Trinidadian cooking.', TRUE),
('bhagi_spinach_saute_trinidadian', 'Bhagi (Spinach Sauté)', 65, 4, 5, 3, 3, 1, 150, NULL, 'research', ARRAY['bhagi (spinach sauté)', 'bhaji', 'spinach bhagi', 'callaloo leaves sauté'], 'traditional', NULL, 1, 'TT', 'Caribbean spinach (bhagi/callaloo leaves) sautéed with garlic, onion and hot pepper. A nutritious vegetable side dish in Indo-Trinidadian cuisine, often eaten for breakfast with roti.', TRUE),
('dhal_split_peas_soup_trinidadian', 'Dhal (Split Peas Soup)', 120, 7, 20, 2, 4, 2, 250, NULL, 'research', ARRAY['dhal (split peas soup)', 'dal tt', 'split peas dhal', 'dhal and rice'], 'traditional', NULL, 1, 'TT', 'Yellow split peas boiled until soft and ''poloured'' (seasoned) with sautéed garlic, cumin (jeera) and turmeric. A cornerstone of Trinidadian daily cooking, eaten with rice and curries at lunch.', TRUE),
('crab_and_callaloo_trinidadian', 'Crab and Callaloo', 160, 14, 8, 8, 3, 2, 300, NULL, 'research', ARRAY['crab and callaloo', 'callaloo and crab tt', 'sunday callaloo'], 'traditional', NULL, 1, 'TT', 'The classic version of callaloo with whole crab pieces simmered in the greens and coconut milk. A Sunday lunch centrepiece in Trinidad and Tobago, often served with rice and macaroni pie.', TRUE),
('pigeon_peas_and_rice_trinidadian', 'Pigeon Peas and Rice', 190, 7, 36, 3, 5, 2, 250, NULL, 'research', ARRAY['pigeon peas and rice', 'gungo peas and rice', 'rice and peas tt', 'pigeon peas rice'], 'traditional', NULL, 1, 'TT', 'Rice cooked with pigeon peas (gungo peas), coconut milk, fresh herbs and seasonings. A fundamental side dish in Trinidadian cooking, especially at Sunday lunch and festive occasions.', TRUE),
('provisions_boiled_trinidadian', 'Provisions (Boiled)', 130, 2, 28, 1, 3, 3, 200, NULL, 'research', ARRAY['provisions (boiled)', 'ground provisions tt', 'boiled ground provisions', 'root vegetables tt'], 'traditional', NULL, 1, 'TT', 'A mixed plate of boiled ground provisions — dasheen, yam, eddoe, sweet potato, cassava and plantain. A traditional Afro-Trinidadian side dish served with stewed meat and callaloo on Sundays.', TRUE),
('stewed_chicken_trinidadian', 'Stewed Chicken', 230, 26, 8, 10, 1, 5, 200, NULL, 'research', ARRAY['stewed chicken', 'brown stew chicken tt', 'stew chicken tt'], 'traditional', NULL, 1, 'TT', 'Chicken pieces browned in caramelised sugar, then stewed with tomatoes, onion, garlic, ketchup and local seasonings. The quintessential Sunday lunch protein in Afro-Trinidadian cooking, served with rice and peas.', TRUE),
('pork_chow_mein_trinidadian', 'Pork Chow Mein', 200, 12, 26, 6, 2, 3, 300, NULL, 'research', ARRAY['pork chow mein', 'trinidad chow mein', 'chinese-trini chow mein'], 'street_food', NULL, 1, 'TT', 'Stir-fried noodles with pork, vegetables and soy sauce — a dish reflecting Trinidad''s significant Chinese-Trinidadian culinary influence. Sold at Chinese-Trinidadian takeaway shops and at fairs.', TRUE),
('wonton_soup_tt_style_trinidadian', 'Wonton Soup (TT Style)', 130, 9, 16, 3, 1, 2, 350, NULL, 'research', ARRAY['wonton soup (tt style)', 'chinese tt wonton soup', 'trinidad wonton'], 'street_food', NULL, 1, 'TT', 'Clear broth soup with pork or shrimp wontons — a Chinese-Trinidadian staple with local adaptations including shadow beni and pepper sauce as accompaniments. Popular at Chinese-Trinidadian restaurants.', TRUE),
('shark_fin_soup_tt_chinese_style_trinidadian', 'Shark Fin Soup (TT Chinese Style)', 110, 8, 12, 3, 1, 2, 300, NULL, 'research', ARRAY['shark fin soup (tt chinese style)', 'chinese-trinidadian soup', 'shark fin-style soup tt'], 'street_food', NULL, 1, 'TT', 'A soup inspired by Chinese-Trinidadian culinary tradition, now typically made without actual shark fin, served at Chinese-Trinidadian community events. Thick, flavourful and associated with festive occasions.', TRUE),
('fried_rice_chinese_tt_trinidadian', 'Fried Rice (Chinese-TT)', 195, 7, 32, 5, 1, 2, 250, NULL, 'research', ARRAY['fried rice (chinese-tt)', 'chinese fried rice tt', 'trinidad fried rice'], 'street_food', NULL, 1, 'TT', 'Fried rice with eggs, mixed vegetables, soy sauce and choice of protein — the Chinese-Trinidadian version adapted with local seasonings. A staple at Chinese takeaway restaurants across Trinidad.', TRUE),
('carnival_pelau_trinidadian', 'Carnival Pelau', 215, 14, 30, 6, 3, 4, 350, NULL, 'research', ARRAY['carnival pelau', 'fete pelau', 'party pelau', 'big pot pelau'], 'carnival_foods', NULL, 1, 'TT', 'Large batch pelau made specifically for Carnival fetes and bashes — cooked in giant pots and served from chafing dishes. Represents communal outdoor cooking central to Trinidad Carnival culture.', TRUE),
('corn_soup_carnival_night_trinidadian', 'Corn Soup (Carnival Night)', 100, 4, 17, 2, 2, 3, 400, NULL, 'research', ARRAY['corn soup (carnival night)', 'jouvert corn soup', 'carnival night soup', 'post-fete corn soup'], 'carnival_foods', NULL, 1, 'TT', 'The larger, thicker version of corn soup sold from pushcarts all night during Carnival — a tradition of eating soup after late-night fetes and jouvert morning. Beloved for its ability to soak up rum.', TRUE),
('aloo_and_channa_wrap_trinidadian', 'Aloo and Channa Wrap', 285, 9, 46, 8, 5, 3, 200, 200, 'research', ARRAY['aloo and channa wrap', 'aloo channa roti', 'channa aloo wrap'], 'street_food', NULL, 1, 'TT', 'Curried potato and chickpeas wrapped in dhalpuri or sada roti — a popular vegetarian roti shop combination and Carnival street food option.', TRUE),
('phulouri_festival_version_trinidadian', 'Phulouri (Festival Version)', 300, 8, 38, 14, 3, 1, 100, 18, 'research', ARRAY['phulouri (festival version)', 'festival pholourie', 'divali phulouri'], 'carnival_foods', NULL, 1, 'TT', 'Larger, festive version of pholourie made for Indian cultural festivals like Divali and Phagwa, fried fresh and served hot with multiple chutneys. Central to Hindu religious food offerings.', TRUE),
('pera_coconut_pera_trinidadian', 'Pera (Coconut Pera)', 390, 3, 60, 16, 4, 52, 40, 20, 'research', ARRAY['pera (coconut pera)', 'coconut pera tt', 'indian coconut sweet'], 'traditional_sweets', NULL, 1, 'TT', 'A traditional Indian-Trinidadian sweet made from grated coconut cooked with milk and sugar until thick and chewy, formed into balls or squares. Made for Divali and Hindu religious celebrations.', TRUE),
('butter_bread_trinidadian', 'Butter Bread', 285, 7, 46, 9, 2, 6, 100, NULL, 'research', ARRAY['butter bread', 'trinidad white bread', 'bakery butter bread'], 'traditional', NULL, 1, 'TT', 'A slightly enriched white bread made with butter, baked in Trinidadian bakeries. Softer and richer than hops bread, it is eaten as toast for breakfast or as sandwich bread throughout the islands.', TRUE),
('currant_roll_trinidadian', 'Currant Roll', 320, 6, 52, 11, 2, 22, 80, 80, 'research', ARRAY['currant roll', 'raisin roll tt', 'currant pastry tt'], 'traditional_sweets', NULL, 1, 'TT', 'Pastry dough rolled with a sweet currant (raisin) filling and baked into a swirl. A traditional Trinidadian bakery item, popular for morning snacks and afternoon tea.', TRUE),
('pine_tart_trinidadian', 'Pine Tart', 295, 4, 46, 12, 1, 20, 80, 80, 'research', ARRAY['pine tart', 'pineapple tart tt', 'pine tart guyana style', 'pine tart bakery'], 'traditional_sweets', NULL, 1, 'TT', 'Shortcrust pastry filled with spiced pineapple jam, baked into squares or triangles. A beloved Trinidadian and Guyanese bakery pastry, sold at every local bakery and school tuck shop.', TRUE),
('tennis_roll_sandwich_trinidadian', 'Tennis Roll Sandwich', 275, 9, 40, 9, 1, 6, 120, NULL, 'research', ARRAY['tennis roll sandwich', 'tennis roll', 'sweet bread sandwich tt'], 'street_food', NULL, 1, 'TT', 'A soft, slightly sweet bread roll used for sandwiches. Tennis rolls are a Trinidadian bakery staple filled with various meats, cheese or vegetables and sold at school canteens and roadside stalls.', TRUE),
('float_fried_dumpling_trinidadian', 'Float (Fried Dumpling)', 295, 6, 44, 11, 2, 2, 100, 50, 'research', ARRAY['float (fried dumpling)', 'float bake', 'fried float', 'yeasted bake'], 'traditional', NULL, 1, 'TT', 'Slightly larger, puffier version of fry bake — a deep-fried yeasted bread that floats in the oil as it cooks. Eaten with saltfish, smoked herring or sardines for breakfast in Trinidad.', TRUE),
('fried_dumplings_boil_n_fry_trinidadian', 'Fried Dumplings (Boil n Fry)', 280, 6, 42, 10, 2, 1, 100, 45, 'research', ARRAY['fried dumplings (boil n fry)', 'boil and fry dumplings', 'fried boiled dumplings tt'], 'traditional', NULL, 1, 'TT', 'Dumplings that are first boiled then fried — a two-step cooking method giving a crispy exterior and chewy interior. A street food and breakfast item particularly popular in South and Central Trinidad.', TRUE),
('peanut_brittle_tt_trinidadian', 'Peanut Brittle (TT)', 490, 12, 56, 27, 3, 50, 50, 20, 'research', ARRAY['peanut brittle (tt)', 'nut brittle tt', 'peanut sweet tt', 'groundnut brittle'], 'traditional_sweets', NULL, 1, 'TT', 'Caramelised sugar poured over roasted peanuts and set into brittle slabs or balls. Sold by street vendors and at markets, school fairs and Carnival — a traditional Caribbean confection.', TRUE),
('sorbet_local_fruit_sorbet_trinidadian', 'Sorbet (Local Fruit Sorbet)', 110, 0, 27, 0, 1, 25, 100, NULL, 'research', ARRAY['sorbet (local fruit sorbet)', 'tropical sorbet tt', 'guava sorbet', 'soursop sorbet'], 'traditional_sweets', NULL, 1, 'TT', 'Refreshing sorbet made from local tropical fruits like soursop, guava, pommecythere or passion fruit — served at ice cream parlours and beach vendors across Trinidad and Tobago.', TRUE),
('snowcone_trinidadian', 'Snowcone', 90, 0, 22, 0, 0, 22, 200, NULL, 'research', ARRAY['snowcone', 'shaved ice tt', 'snow cone tt', 'ice block'], 'street_food', NULL, 1, 'TT', 'Shaved ice drenched in vibrantly coloured sweet syrups — sold by roadside snowcone vendors across Trinidad, especially popular with children and at Carnival. Flavours include cherry, soursop and tamarind.', TRUE),
('ice_cream_cone_street_vendor_trinidadian', 'Ice Cream Cone (Street Vendor)', 230, 4, 30, 11, 1, 24, 120, NULL, 'research', ARRAY['ice cream cone (street vendor)', 'street ice cream tt', 'cart ice cream', 'mobile ice cream tt'], 'street_food', NULL, 1, 'TT', 'Soft-serve or hand-dipped ice cream sold from bicycle-mounted cart vendors and motorbike trucks across Trinidad. A childhood classic, especially beloved in the late afternoon.', TRUE),
('freezer_pop_paleta_trinidadian', 'Freezer Pop (Paleta)', 75, 0, 18, 0, 0, 17, 80, 80, 'research', ARRAY['freezer pop (paleta)', 'frozen juice pop tt', 'freezy pop', 'ice pop tt'], 'street_food', NULL, 1, 'TT', 'Homemade frozen juice pops made from local fruit juices (soursop, pineapple, passion fruit) poured into plastic sleeves and frozen. Sold by schoolchildren and vendors as an affordable cooling treat.', TRUE),
('pone_sweet_potato_pone_trinidadian', 'Pone (Sweet Potato Pone)', 285, 3, 50, 9, 3, 30, 100, NULL, 'research', ARRAY['pone (sweet potato pone)', 'sweet potato pone', 'pone cake tt', 'cassava pone'], 'traditional_sweets', NULL, 1, 'TT', 'A dense, sticky baked pudding made from grated sweet potato, coconut, spices and brown sugar — a traditional Afro-Trinidadian sweet associated with village life and harvest celebrations.', TRUE),
('coconut_pone_trinidadian', 'Coconut Pone', 335, 3, 48, 16, 4, 35, 100, NULL, 'research', ARRAY['coconut pone', 'pure coconut pone', 'baked coconut pudding tt'], 'traditional_sweets', NULL, 1, 'TT', 'Baked pudding made primarily from grated coconut and brown sugar. Denser and more intensely coconut-flavoured than other pone varieties, this is a cherished Trinidadian dessert.', TRUE),
('sponge_cake_bakery_trinidadian', 'Sponge Cake (Bakery)', 340, 5, 52, 13, 1, 32, 100, NULL, 'research', ARRAY['sponge cake (bakery)', 'vanilla sponge tt', 'bakery sponge cake'], 'traditional_sweets', NULL, 1, 'TT', 'Light vanilla sponge cake sold at Trinidadian bakeries, often with fruit jam filling and icing. A staple bakery item enjoyed for birthdays, parties and everyday indulgence.', TRUE),
('red_velvet_cake_trinidadian', 'Red Velvet Cake', 380, 5, 54, 17, 1, 36, 100, NULL, 'research', ARRAY['red velvet cake', 'red velvet tt', 'red cake tt'], 'traditional_sweets', NULL, 1, 'TT', 'A popular cake at Trinidadian bakeries and celebrations — red-tinted chocolate cake with cream cheese icing. Widely adopted into Trinidadian dessert culture and now a standard at events and parties.', TRUE),
('banana_bread_tt_style_trinidadian', 'Banana Bread (TT Style)', 270, 4, 44, 9, 2, 22, 100, NULL, 'research', ARRAY['banana bread (tt style)', 'trini banana bread', 'coconut banana loaf tt'], 'traditional_sweets', NULL, 1, 'TT', 'Moist banana bread made with overripe local bananas, often incorporating coconut, spices or rum-soaked raisins. A popular home-baked treat and bakery item in Trinidad and Tobago.', TRUE),
('rose_water_sweet_biscuit_trinidadian', 'Rose Water Sweet Biscuit', 460, 6, 64, 21, 1, 26, 50, 15, 'research', ARRAY['rose water sweet biscuit', 'rose water cookies tt', 'indian wedding biscuit tt'], 'traditional_sweets', NULL, 1, 'TT', 'Buttery shortbread-style biscuits flavoured with rose water — made for Indian-Trinidadian weddings and religious ceremonies. Fragrant and crumbly, they are part of the sweets distributed at Hindu pujas.', TRUE),
('gizzada_pinwheel_trinidadian', 'Gizzada (Pinwheel)', 350, 3, 52, 15, 3, 34, 60, 60, 'research', ARRAY['gizzada (pinwheel)', 'coconut tart tt', 'pinwheel tart', 'gizzarda tt'], 'traditional_sweets', NULL, 1, 'TT', 'A pastry tart with a pinched pastry shell filled with sweetened grated coconut mixed with ginger and brown sugar. Popular across the Caribbean including Trinidad, with Jamaican origins.', TRUE),
('chip_chip_fritters_trinidadian', 'Chip Chip Fritters', 195, 14, 18, 7, 1, 1, 100, NULL, 'research', ARRAY['chip chip fritters', 'shellfish fritters tt', 'mini clam fritters'], 'street_food', NULL, 1, 'TT', 'Tiny local shellfish mixed into a seasoned batter and deep-fried into crispy fritters. A coastal delicacy from the beaches of South Trinidad and Tobago, sold by seaside vendors.', TRUE),
('crab_cakes_tt_style_trinidadian', 'Crab Cakes (TT Style)', 210, 16, 14, 10, 1, 1, 100, 50, 'research', ARRAY['crab cakes (tt style)', 'crab cake trinidad', 'local crab cakes'], 'street_food', NULL, 1, 'TT', 'Crab meat mixed with local seasonings, shadow beni and pepper, formed into cakes and pan-fried. A Trinidadian seafood dish popular at beach restaurants and seafood vendors in Tobago and coastal areas.', TRUE),
('shark_steak_grilled_trinidadian', 'Shark Steak (Grilled)', 185, 30, 0, 7, 0, 0, 150, NULL, 'research', ARRAY['shark steak (grilled)', 'grilled shark tt', 'shark steak maracas'], 'street_food', NULL, 1, 'TT', 'Grilled shark steak seasoned with local green seasoning, lime and scotch bonnet. Served at Maracas Beach and coastal vendors — a Trinidadian seafood specialty beyond the famous bake and shark preparation.', TRUE),
('carite_king_fish_steak_trinidadian', 'Carite (King Fish) Steak', 175, 28, 0, 7, 0, 0, 150, NULL, 'research', ARRAY['carite (king fish) steak', 'king fish steak tt', 'carite fish tt', 'spanish mackerel tt'], 'street_food', NULL, 1, 'TT', 'Grilled or pan-fried carite (Spanish mackerel / king fish) steaks seasoned with green seasoning and lime. A popular beach food and restaurant dish in Trinidad''s fishing communities.', TRUE),
('crayfish_crab_curry_trinidadian', 'Crayfish (Crab) Curry', 180, 22, 5, 8, 1, 2, 200, NULL, 'research', ARRAY['crayfish (crab) curry', 'river crab curry tt', 'crayfish curry tt'], 'traditional', NULL, 1, 'TT', 'Freshwater crayfish or small river crab curried in the Trinidadian style with curry powder, shadow beni and scotch bonnet. A delicacy from the river communities of Trinidad''s interior.', TRUE),
('curried_cascadura_trinidadian', 'Curried Cascadura', 190, 24, 4, 8, 1, 1, 200, NULL, 'research', ARRAY['curried cascadura', 'cascadu curry', 'cascadoux curry tt', 'curried cascadoux'], 'traditional', NULL, 1, 'TT', 'Cascadura (an armoured catfish unique to Trinidad) cooked in Trinidad curry — a legendary dish tied to a folk belief that whoever eats cascadura will return to Trinidad to die. A symbol of the island''s unique biodiversity.', TRUE),
('curried_agouti_trinidadian', 'Curried Agouti', 215, 26, 3, 11, 0, 1, 200, NULL, 'research', ARRAY['curried agouti', 'agouti curry tt', 'wild game curry tt'], 'traditional', NULL, 1, 'TT', 'Agouti (a large native rodent) slow-cooked in Trinidad-style curry. A traditional wild game dish found in rural areas of Trinidad, associated with forest communities and hunting culture.', TRUE),
('curried_manicou_trinidadian', 'Curried Manicou', 200, 24, 3, 10, 0, 1, 200, NULL, 'research', ARRAY['curried manicou', 'manicou curry tt', 'opossum curry tt'], 'traditional', NULL, 1, 'TT', 'Manicou (opossum) cooked in local curry — a traditional bush meat dish from rural Trinidad. Rarely found outside rural communities, it represents the indigenous and African hunting traditions of the island.', TRUE),
('pacro_water_trinidadian', 'Pacro Water', 45, 6, 2, 1, 0, 1, 300, NULL, 'research', ARRAY['pacro water', 'oyster water tt', 'pacro soup', 'oyster broth tt'], 'street_food', NULL, 1, 'TT', 'A clear broth soup made from boiling fresh oysters (pacro) with herbs — sold by seaside vendors as a reputed aphrodisiac and general tonic. A distinctly Trinidadian coastal food tradition.', TRUE),
('ovaltine_tt_style_trinidadian', 'Ovaltine (TT Style)', 115, 4, 20, 3, 1, 16, 250, NULL, 'research', ARRAY['ovaltine (tt style)', 'ovaltine milk tt', 'malt drink tt'], 'street_food', NULL, 1, 'TT', 'Ovaltine malt drink mixed hot or cold with full-fat milk — a classic Trinidadian school canteen and street vendor beverage. Paired with hops bread and cheese for generations of Trinidadian breakfast.', TRUE),
('milo_trinidadian', 'Milo', 110, 4, 19, 2, 0, 15, 250, NULL, 'research', ARRAY['milo', 'milo drink tt', 'chocolate malt tt'], 'street_food', NULL, 1, 'TT', 'Nestlé Milo chocolate malt drink prepared hot or iced with milk — competing with Ovaltine as a favourite school canteen and street vendor drink across Trinidad and Tobago.', TRUE),
('stag_beer_trinidadian', 'Stag Beer', 43, 0, 3, 0, 0, 0, 330, NULL, 'research', ARRAY['stag beer', 'stag lager tt', 'stag beer trinidad'], 'street_food', NULL, 1, 'TT', 'A Trinidadian beer positioned as the ''man''s beer'' — slightly stronger and fuller-bodied than Carib. Brewed locally and a staple at rum shops, limes and Carnival fetes.', TRUE),
('rum_punch_trinidadian', 'Rum Punch', 175, 0, 20, 0, 0, 18, 200, NULL, 'research', ARRAY['rum punch', 'trinidad rum punch', 'caribbean rum punch', 'tt rum cocktail'], 'carnival_foods', NULL, 1, 'TT', 'A cocktail made with Trinidad rum, lime juice, sugar, Angostura bitters and water or juice — following the island''s ''one sour, two sweet, three strong, four weak'' rum punch formula. A Carnival essential.', TRUE),
('puncheon_rum_trinidadian', 'Puncheon Rum', 220, 0, 0, 0, 0, 0, 60, NULL, 'research', ARRAY['puncheon rum', 'trinidad puncheon', 'overproof rum tt', 'white rum tt puncheon'], 'carnival_foods', NULL, 1, 'TT', 'Overproof white rum (75% ABV) produced in Trinidad — the strongest locally made spirit, used in Carnival mixes and bush remedies. Drinking puncheon neat is a Trinidadian rite of passage at fetes.', TRUE),
('fish_broth_trinidadian', 'Fish Broth', 85, 12, 6, 2, 1, 2, 350, NULL, 'research', ARRAY['fish broth', 'fresh fish broth tt', 'fisherman''s broth', 'fish soup tt'], 'street_food', NULL, 1, 'TT', 'A light yet flavourful broth made from fresh fish, ground provisions, dumplings and local herbs. Sold by vendors early in the morning — especially fishermen communities in Cedros, Carenage and Tobago.', TRUE),
('curried_lobster_tobago_trinidadian', 'Curried Lobster (Tobago)', 195, 24, 4, 9, 0, 2, 200, NULL, 'research', ARRAY['curried lobster (tobago)', 'tobago lobster curry', 'coconut lobster tt', 'curried crayfish tobago'], 'traditional', NULL, 1, 'TT', 'Lobster tails or whole spiny lobster cooked in Tobago-style curry — milder and sweeter than Trinidad curry, using coconut milk. A signature dish of Tobago''s seafood culture and beach restaurants.', TRUE),
('pelau_pigeon_peas_and_saltfish_trinidadian', 'Pelau (Pigeon Peas and Saltfish)', 195, 10, 30, 5, 4, 2, 300, NULL, 'research', ARRAY['pelau (pigeon peas and saltfish)', 'saltfish pelau', 'lent pelau tt'], 'traditional', NULL, 1, 'TT', 'A Lenten and lean-time version of pelau made with saltfish instead of meat, combined with pigeon peas and rice in coconut milk. Popular during Catholic and other Christian fasting periods in Trinidad.', TRUE),
('oil_down_tobago_trinidadian', 'Oil Down (Tobago)', 280, 14, 30, 12, 4, 3, 350, NULL, 'research', ARRAY['oil down (tobago)', 'tobago oil down', 'breadfruit oildown', 'one pot oildown'], 'traditional', NULL, 1, 'TT', 'Tobago''s national dish — a one-pot meal of breadfruit, mixed provisions, salted pork, chicken and callaloo leaves simmered in coconut milk until all the liquid is absorbed (''downs into the oil''). Cooked in a large pot for communal gatherings.', TRUE),
('crab_and_dumpling_tobago_trinidadian', 'Crab and Dumpling (Tobago)', 280, 20, 28, 10, 2, 2, 350, NULL, 'research', ARRAY['crab and dumpling (tobago)', 'tobago crab and dumpling', 'crab curry and dumpling', 'sunday crab tobago'], 'traditional', NULL, 1, 'TT', 'Whole blue crabs cooked in a rich curry-spiced coconut milk sauce, served with boiled dumplings. The signature dish of Tobago, typically prepared on Sundays and at beach cookouts.', TRUE),
('eddoe_chips_trinidadian', 'Eddoe Chips', 450, 3, 60, 22, 4, 3, 100, NULL, 'research', ARRAY['eddoe chips', 'fried eddoe chips', 'taro chip tt'], 'snacks', NULL, 1, 'TT', 'Thinly sliced eddoe (small taro) fried into chips — a locally produced snack utilising Trinidad''s traditional root vegetables. Sold packaged in some supermarkets and made fresh at home.', TRUE),
('dasheen_chips_trinidadian', 'Dasheen Chips', 460, 3, 62, 22, 4, 2, 100, NULL, 'research', ARRAY['dasheen chips', 'taro chips tt', 'fried dasheen chips'], 'snacks', NULL, 1, 'TT', 'Thinly sliced dasheen (taro) deep-fried into crispy chips. A traditional Caribbean root vegetable snack, less common commercially than cassava chips but enjoyed at home and community events.', TRUE),
('boiled_corn_husk_tamale_trinidadian', 'Boiled Corn Husk Tamale', 210, 5, 35, 7, 3, 2, 150, 150, 'research', ARRAY['boiled corn husk tamale', 'corn husk tamale tt', 'boiled cornmeal package'], 'carnival_foods', NULL, 1, 'TT', 'Cornmeal mixture steamed in corn husks, similar to pastelle but plainer and sold at Carnival street stalls. Reflects the Amerindian and Latin American culinary influence in Trinidad''s food heritage.', TRUE),
('pepper_pot_christmas_trinidadian', 'Pepper Pot (Christmas)', 195, 18, 8, 10, 1, 4, 200, NULL, 'research', ARRAY['pepper pot (christmas)', 'trinidad pepper pot', 'cassareep stew', 'christmas pepper pot tt'], 'carnival_foods', NULL, 1, 'TT', 'A preserved meat stew darkened with cassareep (concentrated cassava juice) and spiced with cinnamon and hot pepper — a traditional Amerindian-origin dish eaten at Christmas alongside pastelle and black cake.', TRUE),
('sweet_bread_easter_trinidadian', 'Sweet Bread (Easter)', 340, 6, 54, 12, 2, 24, 80, 80, 'research', ARRAY['sweet bread (easter)', 'easter sweet bread tt', 'coconut sweet bread', 'spiced bun tt'], 'carnival_foods', NULL, 1, 'TT', 'An enriched, sweet, spiced bread with coconut, cherries and mixed fruit, baked for Easter. Also called ''sweet bread'' year-round at Trinidadian bakeries but the Easter version is spiced more heavily.', TRUE),
('hot_cross_bun_tt_trinidadian', 'Hot Cross Bun (TT)', 295, 6, 48, 9, 2, 18, 80, 80, 'research', ARRAY['hot cross bun (tt)', 'trinidad hot cross buns', 'good friday buns tt', 'spiced easter bun'], 'carnival_foods', NULL, 1, 'TT', 'Spiced sweet buns with currants and a cross of white icing, baked for Good Friday in Trinidad. Sold at bakeries starting Holy Week — a tradition from British colonial influence now deeply embedded in local culture.', TRUE),
('doubles_with_slight_pepper_trinidadian', 'Doubles with Slight Pepper', 278, 8, 42, 9, 4, 3, 150, 150, 'research', ARRAY['doubles with slight pepper', 'doubles slight', 'slight pepper doubles'], 'street_food', NULL, 1, 'TT', 'The most ordered variation of Trinidad''s doubles — identical to standard doubles but with just a small amount of pepper sauce. The phrase ''slight'' is quintessentially Trinidadian street food vocabulary.', TRUE),
('full_pepper_doubles_trinidadian', 'Full Pepper Doubles', 285, 8, 42, 9, 4, 3, 155, 155, 'research', ARRAY['full pepper doubles', 'plenty pepper doubles', 'hot doubles'], 'street_food', NULL, 1, 'TT', 'Doubles loaded with extra pepper sauce — the ''full pepper'' order at a doubles stall. A beloved breakfast challenge for those who can handle the scotch bonnet heat of Trinidad''s fiery condiments.', TRUE),
('dhal_puri_and_curry_trinidadian', 'Dhal Puri and Curry', 390, 16, 54, 13, 6, 3, 350, 350, 'research', ARRAY['dhal puri and curry', 'dhal puri wrap', 'roti wrap tt', 'roti and curry'], 'street_food', NULL, 1, 'TT', 'A complete meal of dhalpuri roti wrapped with curried channa, aloo and/or chicken — the most popular roti shop order. Represents the full expression of Indo-Trinidadian street food culture.', TRUE),
('split_peas_soup_trinidadian', 'Split Peas Soup', 130, 7, 22, 2, 5, 3, 350, NULL, 'research', ARRAY['split peas soup', 'dhal soup tt', 'pea soup tt', 'sunday soup tt'], 'traditional', NULL, 1, 'TT', 'Thick yellow split pea soup with dumplings, pumpkin and ground provisions — a staple of Trinidadian Sunday lunch culture, simmered for hours with smoked meats and local vegetables.', TRUE),
('pig_tail_soup_trinidadian', 'Pig Tail Soup', 165, 10, 14, 7, 2, 2, 350, NULL, 'research', ARRAY['pig tail soup', 'salted pig tail soup', 'pigtail soup tt'], 'traditional', NULL, 1, 'TT', 'A hearty soup made with salted pig tail, ground provisions, dumplings and vegetables. A traditional Afro-Trinidadian dish demonstrating the nose-to-tail cooking tradition introduced during the era of enslavement.', TRUE),
('heera_black_eyed_peas_trinidadian', 'Heera (Black Eyed Peas)', 145, 9, 24, 2, 6, 2, 200, NULL, 'research', ARRAY['heera (black eyed peas)', 'black eyed peas tt', 'cowpea curry tt', 'black eye and rice'], 'traditional', NULL, 1, 'TT', 'Black-eyed peas cooked with coconut milk, coconut cream, shadow beni and hot pepper. A traditional Afro-Trinidadian side dish with strong West African roots, eaten with rice for Sunday lunch.', TRUE),
