('zaboca_avocado_shake_trinidadian', 'Zaboca (Avocado) Shake', 165, 3, 16, 11, 4, 12, 250, NULL, 'research', ARRAY['zaboca (avocado) shake', 'avocado shake tt', 'zaboca drink', 'sweet avocado shake tt'], 'street_food', NULL, 1, 'TT', 'Blended avocado (zaboca) with condensed milk, sugar and ice — a sweet, creamy Trinidadian drink. Zaboca is eaten sweet in Trinidad unlike most other countries where it is eaten savoury.', TRUE),
('pommerac_juice_trinidadian', 'Pommerac Juice', 45, 0, 11, 0, 1, 9, 250, NULL, 'research', ARRAY['pommerac juice', 'water apple juice tt', 'malay rose apple juice', 'pommerac drink'], 'street_food', NULL, 1, 'TT', 'Juice made from pommerac (Malay rose apple / water apple) — a crisp, bell-shaped tropical fruit abundant in Trinidad. A refreshing light juice sold fresh at fruit stalls and juice bars.', TRUE),
('malta_carib_malta_trinidadian', 'Malta (Carib Malta)', 145, 1, 34, 0, 0, 28, 330, NULL, 'research', ARRAY['malta (carib malta)', 'carib malta tt', 'malt beverage tt', 'malta drink'], 'street_food', NULL, 1, 'TT', 'A non-alcoholic malt beverage produced by Carib Brewery — sweet, dark, and rich with a thick malt flavour. A beloved Trinidadian non-alcoholic drink traditionally given to nursing mothers and drinkers alike.', TRUE),
('cream_soda_solo_trinidadian', 'Cream Soda (Solo)', 105, 0, 26, 0, 0, 26, 330, NULL, 'research', ARRAY['cream soda (solo)', 'solo cream soda', 'tt cream soda', 'solo soda tt'], 'street_food', NULL, 1, 'TT', 'Solo brand cream soda — a sweet, vanilla-flavoured fizzy drink that is uniquely beloved in Trinidad. Solo Beverages is a local brand producing cream soda, kola champagne and other sodas iconic to Trinidadian culture.', TRUE),
('kola_champagne_solo_trinidadian', 'Kola Champagne (Solo)', 105, 0, 26, 0, 0, 26, 330, NULL, 'research', ARRAY['kola champagne (solo)', 'solo kola champagne', 'kola champ tt', 'kola nut soda tt'], 'street_food', NULL, 1, 'TT', 'A uniquely Trinidadian fizzy kola-nut flavoured soft drink produced by Solo Beverages. Kola Champagne has a distinctive slightly bitter, sweet flavour with no equivalent elsewhere — a true Trinidadian beverage icon.', TRUE),
('lemonade_local_style_trinidadian', 'Lemonade (Local Style)', 42, 0.1, 10.5, 0.0, 0.0, 10.2, 250, NULL, 'research', ARRAY['lemonade (local style)', 'limeade', 'citrus punch'], 'beverage', NULL, 1, 'TT', 'Fresh West Indian lime squeezed with sugar and water; standard roadside refreshment', TRUE),
