('ovaltine_drink_trinidadian', 'Ovaltine Drink', 78, 3.0, 14.0, 1.2, 0.5, 12.0, 250, NULL, 'research', ARRAY['ovaltine drink', 'milo drink', 'horlicks drink'], 'beverage', NULL, 1, 'TT', 'Malted milk drink popular as morning or evening beverage in Trinidadian households', TRUE),
